// // This module implements a 16-bit SRAM cell with read and write operations.
// Inputs: address (4 bits), data_in (16 bits), we (write disable), clk (clock).
// Outputs: data_out (16 bits).

// When we is low, the value of data_in should be written to the memory location specified by address on the rising edge of clk.
// When we is high, the value at the specified memory address should be output on data_out.
module SRAM_16bit (
    input [3:0] address,
    input [15:0] data_in,
    input we,
    input clk,
    output reg [15:0] data_out
);
    reg [15:0] memory [0:15]; // 16 locations of 16-bit memory

    always @(posedge clk) begin
        if (we) begin
            memory[address] <= data_in; // Write operation
        end else begin
            data_out <= memory[address]; // Read operation
        end
    end
endmodule

